{{ safesubst:<noinclude/>#invoke:Unsubst||date=__DATE__|$B=
{{Fix
| subst     = <includeonly>{{subst:substcheck}}</includeonly>
| link      = Wikipedia:Manual of Style/Words to watch
| text      = when defined as?
| title     = {{{1|{{{reason|The preceding text may be too imprecise or indirect for Wikipedia's standards.}}}}}}
| date      = {{{date|}}}
| cat-date  = Category:Wikipedia articles needing clarification
}}}}<noinclude>
{{Documentation}}
<!-- Categories go on the /doc subpage, and interwikis go on Wikidata. -->
</noinclude>

